1	// Exercise catalog types. The catalog is STATIC source-of-truth metadata
2	// about every exercise Flux supports. Workout programs (runtime data in
3	// IndexedDB) reference catalog entries by id.
4	
5	import type { EquipmentKind } from './equipmentCatalog';
6	
7	export interface Exercise {
8	  id: string;
9	  name: string;
10	  // Muscle groups primarily worked. Required; validated by scripts/validate-catalog.ts.
11	  muscleGroups: string[];
12	  // Equipment required to perform this exercise. AND semantics — the user
13	  // needs ALL listed kinds. Use ['bodyweight'] for unequipped exercises.
14	  equipmentRequired: EquipmentKind[];
15	  // Optional alternative equipment groups. Each inner array is one viable
16	  // substitution for equipmentRequired. Example: a kettlebell row could be
17	  // performed with a dumbbell, so equipmentAlternatives = [['dumbbell']].
18	  // Unused for most entries — reserved for PR-B / PR-C consumption.
19	  equipmentAlternatives?: EquipmentKind[][];
20	  // YouTube video id for a technique demo, if available.
21	  demoVideoId?: string;
22	  // Offset in seconds into the demo video where the technique starts.
23	  demoVideoStart?: number;
24	  // Short cueing / safety note that should be shown alongside the exercise.
25	  techniqueNote?: string;
26	  // Whether the exercise typically uses external weight (kettlebell, dumbbell,
27	  // barbell). Bodyweight / mobility entries set this false.
28	  usesWeight: boolean;
29	  // Defaults applied when a program entry omits them.
30	  defaultStartingWeight?: number;
31	  defaultWeightIncrement?: number;
32	}
33	
34	export type ExerciseCatalog = Record<string, Exercise>;
35

