1	import { useCallback, useEffect, useMemo, useState } from 'preact/hooks';
2	import {
3	  workoutKeyForDay,
4	  suggestWeight,
5	  getLastWeight,
6	  buildLatestWeightedMap,
7	} from './logic/progression';
8	import { resolveExercise } from './logic/resolveExercise';
9	import {
10	  DEFAULT_STATE,
11	  deleteLogEntry,
12	  loadLocations,
13	  loadLog,
14	  loadProgram,
15	  loadState,
16	  putLogEntry,
17	  saveState,
18	} from './state';
19	import {
20	  activeInventory,
21	  cloneDefaultLocationsState,
22	  isInventoryConfigured,
23	  type LocationsState,
24	} from '../../data/inventory';
25	import { EQUIPMENT_CATALOG, type EquipmentKind } from '../../data/equipmentCatalog';
26	import {
27	  allowedWeightsForExercise,
28	  isExerciseSupportedByInventory,
29	  missingKindsForExercise,
30	} from './logic/equipmentResolve';
31	import {
32	  applyProgramImportFromFile,
33	  formatProgramImportMessage,
34	} from './logic/exportImport';
35	import type { LogEntry, LogMap, Phase, Program, WorkoutState } from './types';
36	import { ExerciseCard } from './components/ExerciseCard';
37	import { VideoModal } from './components/VideoModal';
38	
39	function getCurrentPhase(program: Program | null, state: WorkoutState): Phase | null {
40	  if (!program) return null;
41	  return program.phases.find((p) => p.id === state.currentPhase) ?? null;
42	}
43	
44	function formatDriftMessage(missing: EquipmentKind[]): string {
45	  const names = missing.map((k) => EQUIPMENT_CATALOG[k]?.name.toLowerCase() ?? k);
46	  let list: string;
47	  if (names.length === 1) list = names[0];
48	  else if (names.length === 2) list = `${names[0]} and ${names[1]}`;
49	  else list = `${names.slice(0, -1).join(', ')}, and ${names[names.length - 1]}`;
50	  return `Requires ${list} — not in your inventory.`;
51	}
52	
53	interface VideoState {
54	  videoId: string;
55	  start?: number;
56	}
57	
58	export function Workouts() {
59	  const [state, setState] = useState<WorkoutState>(DEFAULT_STATE);
60	  const [log, setLog] = useState<LogMap>({});
61	  const [video, setVideo] = useState<VideoState | null>(null);
62	  const [importMessage, setImportMessage] = useState<string | null>(null);
63	  const [loaded, setLoaded] = useState(false);
64	  // Programs are runtime data: they arrive via import or (future) AI
65	  // generation, persisted to the 'program' store in flux-db. No bundled
66	  // default — the empty state below covers a fresh install.
67	  const [program, setProgram] = useState<Program | null>(null);
68	  const [locations, setLocations] = useState<LocationsState>(
69	    cloneDefaultLocationsState,
70	  );
71	
72	  useEffect(() => {
73	    (async () => {
74	      const [s, l, p, loc] = await Promise.all([
75	        loadState(),
76	        loadLog(),
77	        loadProgram(),
78	        loadLocations(),
79	      ]);
80	      setState(s);
81	      setLog(l);
82	      setProgram(p);
83	      setLocations(loc);
84	      setLoaded(true);
85	    })();
86	  }, []);
87	
88	  function triggerProgramImport() {
89	    document
90	      .querySelector<HTMLInputElement>('[data-testid="import-program-input"]')
91	      ?.click();
92	  }
93	
94	  const phase = getCurrentPhase(program, state);
95	  const workoutKey = phase ? workoutKeyForDay(phase, state.globalDay) : null;
96	  const workout = phase && workoutKey && workoutKey !== 'Rest' ? phase.workouts[workoutKey] : null;
97	  const week = Math.floor((state.globalDay - 1) / 7) + 1;
98	
99	  const resolvedExercises = useMemo(
100	    () => workout?.exercises.map(resolveExercise) ?? [],
101	    [workout],
102	  );
103	
104	  const completedCount = useMemo(() => {
105	    if (!workout) return 0;
106	    return resolvedExercises.reduce((count, _ex, i) => {
107	      const key = `${state.globalDay}_${i}`;
108	      return count + (log[key]?.completed ? 1 : 0);
109	    }, 0);
110	  }, [log, state.globalDay, workout, resolvedExercises]);
111	
112	  // Compute latest-weighted-entry-per-exercise once per log change so render
113	  // is O(M) instead of O(M*N) (scanning the full log for every exercise).
114	  const latestWeights = useMemo(() => buildLatestWeightedMap(log), [log]);
115	
116	  const inventory = useMemo(() => activeInventory(locations), [locations]);
117	  const inventoryConfigured = useMemo(
118	    () => isInventoryConfigured(locations),
119	    [locations],
120	  );
121	
122	  const onLog = useCallback(
123	    (key: string, partial: Partial<LogEntry>, options?: { remove?: boolean }) => {
124	      const existing = log[key];
125	      const merged: Partial<LogEntry> = { ...existing, ...partial };
126	
127	      for (const k of Object.keys(merged) as (keyof LogEntry)[]) {
128	        if (merged[k] === undefined) delete merged[k];
129	      }
130	
131	      const meaningless =
132	        options?.remove ||
133	        (!merged.weight &&
134	          !merged.difficulty &&
135	          !merged.notes &&
136	          !merged.completed);
137	
138	      if (meaningless) {
139	        setLog((prev) => {
140	          if (!(key in prev)) return prev;
141	          const next = { ...prev };
142	          delete next[key];
143	          return next;
144	        });
145	        deleteLogEntry(key).catch(() => {});
146	      } else {
147	        const entry: LogEntry = {
148	          exercise: merged.exercise ?? existing?.exercise ?? '',
149	          day: merged.day ?? existing?.day ?? state.globalDay,
150	          timestamp: merged.timestamp ?? Date.now(),
151	          ...merged,
152	        };
153	        setLog((prev) => ({ ...prev, [key]: entry }));
154	        putLogEntry(key, entry).catch(() => {});
155	      }
156	    },
157	    [log, state.globalDay],
158	  );
159	
160	  function nextDay() {
161	    if (state.globalDay >= 365) return;
162	    let nextPhaseId = state.currentPhase;
163	    const day = state.globalDay + 1;
164	    if (phase && program) {
165	      const daysInPhase = phase.duration_weeks * 7;
166	      if (day > daysInPhase) {
167	        const idx = program.phases.findIndex((p) => p.id === phase.id);
168	        if (idx >= 0 && idx < program.phases.length - 1) {
169	          nextPhaseId = program.phases[idx + 1].id;
170	        }
171	      }
172	    }
