    command: 'npm run build && npx vite preview --port 3030 --strictPort',
    url: 'http://localhost:3030',
    reuseExistingServer: !process.env.CI,
    timeout: 180_000,
  },

  projects: [{ name: 'chromium', use: { browserName: 'chromium' } }],
});

