134	// trimmed. Returns the catalog id or null if no match. Used to migrate
135	// legacy program exports (which referenced exercises by name) into the
136	// id-based shape the catalog uses.
137	export function mapExerciseByName(name: string): string | null {
138	  if (typeof name !== 'string') return null;
139	  const key = name.trim().toLowerCase();
140	  if (!key) return null;
