158	// Normalize a workout's exercises into the id-based shape. Detects format by
159	// sniffing keys: a legacy entry has a `name` field; the new shape has
160	// `exercise_id`. Returns the normalized list plus mapping stats so callers
161	// can surface a one-time toast about how many exercises matched the catalog.
162	function migrateWorkoutExercises(
163	  workout: Record<string, unknown>,
164	  stats: MigrationStats,
165	): WorkoutExercise[] {
166	  const raw = Array.isArray(workout.exercises) ? workout.exercises : [];
167	  const out: WorkoutExercise[] = [];
168	  for (const ex of raw) {
169	    if (!isObject(ex)) continue;
170	    const sets = typeof ex.sets === 'number' ? ex.sets : 0;
171	    const reps = typeof ex.reps === 'string' ? ex.reps : String(ex.reps ?? '');
172	    const rest = typeof ex.rest === 'string' ? ex.rest : '';
173	    const startingWeight =
174	      typeof ex.starting_weight === 'number' ? ex.starting_weight : undefined;
175	    const weightIncrement =
176	      typeof ex.weight_increment === 'number' ? ex.weight_increment : undefined;
177	
178	    if (typeof ex.exercise_id === 'string' && ex.exercise_id.length > 0) {
179	      // Already in new format. Trust the export but still verify the id
180	      // exists in the catalog — unknown ids get the unmapped treatment.
181	      const id = ex.exercise_id;
182	      const mapped = id in EXERCISE_CATALOG;
183	      stats.total++;
184	      if (mapped) stats.mapped++;
185	      else stats.unmapped++;
186	      const entry: WorkoutExercise = { exercise_id: id, sets, reps, rest };
187	      if (startingWeight !== undefined) entry.starting_weight = startingWeight;
188	      if (weightIncrement !== undefined) entry.weight_increment = weightIncrement;
189	      if (!mapped) {
190	        entry.exercise_name =
191	          typeof ex.exercise_name === 'string' ? ex.exercise_name : id;
192	        entry.from_legacy_import = true;
193	      }
194	      out.push(entry);
195	      continue;
196	    }
197	
198	    const name = typeof ex.name === 'string' ? ex.name : '';
199	    if (!name) continue;
200	    stats.total++;
201	    const matched = mapExerciseByName(name);
202	    const entry: WorkoutExercise = {
203	      exercise_id: matched ?? (slugify(name) || 'unknown'),
204	      sets,
205	      reps,
206	      rest,
207	    };
208	    if (startingWeight !== undefined) entry.starting_weight = startingWeight;
209	    if (weightIncrement !== undefined) entry.weight_increment = weightIncrement;
210	    if (matched) {
211	      stats.mapped++;
212	    } else {
213	      stats.unmapped++;
214	      entry.exercise_name = name;
215	      entry.from_legacy_import = true;
216	    }
217	    out.push(entry);
218	  }
219	  return out;
220	}
