222	function migrateProgram(raw: unknown): { program: Program; stats: MigrationStats } | null {
223	  if (!isObject(raw)) return null;
224	  if (!isObject(raw.meta)) return null;
225	  if (!Array.isArray(raw.phases)) return null;
226	
227	  const stats: MigrationStats = { mapped: 0, unmapped: 0, total: 0 };
228	  const phases: Phase[] = [];
229	  for (const ph of raw.phases) {
230	    if (!isObject(ph)) continue;
231	    const workouts: Record<string, Workout> = {};
232	    if (isObject(ph.workouts)) {
233	      for (const [key, w] of Object.entries(ph.workouts)) {
234	        if (!isObject(w)) continue;
235	        workouts[key] = {
236	          name: typeof w.name === 'string' ? w.name : key,
237	          focus: typeof w.focus === 'string' ? w.focus : '',
238	          exercises: migrateWorkoutExercises(w, stats),
239	        };
240	      }
241	    }
242	    phases.push({
243	      id: typeof ph.id === 'string' ? ph.id : '',
244	      name: typeof ph.name === 'string' ? ph.name : '',
245	      duration_weeks:
246	        typeof ph.duration_weeks === 'number' ? ph.duration_weeks : 0,
247	      description:
248	        typeof ph.description === 'string' ? ph.description : undefined,
249	      schedule_pattern: Array.isArray(ph.schedule_pattern)
250	        ? ph.schedule_pattern.filter((d): d is string => typeof d === 'string')
251	        : undefined,
252	      workouts,
253	    });
254	  }
255	
256	  const meta = raw.meta as Record<string, unknown>;
257	  const constraints = isObject(meta.constraints) ? meta.constraints : {};
258	  const program: Program = {
259	    meta: {
260	      startDate: typeof meta.startDate === 'string' ? meta.startDate : '',
261	      version: typeof meta.version === 'string' ? meta.version : '',
262	      principles: Array.isArray(meta.principles)
263	        ? meta.principles.filter((p): p is string => typeof p === 'string')
264	        : [],
265	      constraints: {
266	        mobility_required: constraints.mobility_required === true,
267	        min_mobility_days_per_week:
268	          typeof constraints.min_mobility_days_per_week === 'number'
269	            ? constraints.min_mobility_days_per_week
270	            : 0,
271	      },
272	    },
273	    phases,
274	  };
