278	// Apply an export payload to the current IDB. Sanitizes every entry, merges
279	// (skips keys that already exist), and optionally restores state. Programs in
280	// the payload are migrated to the id-based catalog shape — legacy exports
281	// (with name-based exercises) get name → id mapping via the catalog. Throws
282	// on payloads that don't match the legacy schema so the UI can surface an
283	// error.
284	export async function applyImport(
285	  raw: unknown,
286	  opts: { applyState?: boolean } = {},
287	): Promise<ImportResult> {
288	  if (!raw || typeof raw !== 'object' || Array.isArray(raw)) {
289	    throw new Error('Invalid backup: not an object');
290	  }
291	  const data = raw as Record<string, unknown>;
292	  if (!data.log || typeof data.log !== 'object' || Array.isArray(data.log)) {
293	    throw new Error('Invalid backup: missing or malformed log');
294	  }
295	
296	  const incoming = data.log as Record<string, unknown>;
297	  const keys = Object.keys(incoming);
298	  const existing = await loadLog();
299	
300	  let imported = 0;
301	  let skipped = 0;
302	  const toWrite: Array<{ key: string; entry: LogEntry }> = [];
303	  for (const key of keys) {
304	    if (existing[key]) {
305	      skipped++;
306	      continue;
307	    }
308	    const sanitized = sanitizeLogEntry(incoming[key]);
309	    if (!sanitized) {
310	      skipped++;
311	      continue;
312	    }
313	    const entry: LogEntry = {
314	      exercise: sanitized.exercise ?? '',
315	      day: sanitized.day ?? 0,
316	      timestamp: sanitized.timestamp ?? Date.now(),
317	      ...sanitized,
318	    };
319	    toWrite.push({ key, entry });
320	    imported++;
321	  }
322	  // Single readwrite transaction for the whole batch — avoids per-entry
323	  // transaction overhead on bulk imports.
324	  await putLogEntries(toWrite);
325	
326	  let stateApplied = false;
327	  if (opts.applyState && isObject(data.state)) {
328	    const s = data.state as Record<string, unknown>;
329	    const next: WorkoutState = {
330	      globalDay:
331	        typeof s.globalDay === 'number' && Number.isInteger(s.globalDay) && s.globalDay >= 1
332	          ? s.globalDay
333	          : 1,
334	      currentPhase: typeof s.currentPhase === 'string' ? s.currentPhase : 'p1',
335	    };
336	    await saveState(next);
337	    stateApplied = true;
338	  }
339	
340	  let programApplied = false;
341	  let exerciseMapping: ImportResult['exerciseMapping'];
342	  if (data.program !== undefined) {
343	    const migrated = migrateProgram(data.program);
344	    if (migrated) {
345	      await saveProgram(migrated.program);
346	      programApplied = true;
347	      exerciseMapping = migrated.stats;
348	    }
349	  }
350	
351	  let inventoryApplied = false;
352	  if (data.locations !== undefined) {
353	    // Absence means "don't touch existing inventory"; presence means restore
354	    // the sanitized payload. Unknown EquipmentKind keys and bad weights get
355	    // dropped by sanitizeLocationsState.
356	    const sanitized = sanitizeLocationsState(data.locations);
357	    await saveLocations(sanitized);
358	    inventoryApplied = true;
359	  }
360	
361	  return {
362	    imported,
363	    skipped,
364	    total: keys.length,
365	    stateApplied,
366	    programApplied,
367	    inventoryApplied,
368	    ...(exerciseMapping ? { exerciseMapping } : {}),
369	  };
370	}
371	
372	function isObject(v: unknown): v is Record<string, unknown> {
373	  return typeof v === 'object' && v !== null && !Array.isArray(v);
374	}
375	
376	// Apply just a program to flux-db. Accepts either a bare program object
377	// (`{meta, phases}`) or a backup envelope where it pulls the `program`
378	// field out. Never touches the log or workout state stores. Throws on
379	// shapes we can't make sense of — the empty-state CTA surfaces these
380	// errors inline.
381	export async function applyProgramImport(raw: unknown): Promise<ProgramImportResult> {
382	  if (!raw || typeof raw !== 'object' || Array.isArray(raw)) {
383	    throw new Error('Invalid program file: not an object');
384	  }
385	  const data = raw as Record<string, unknown>;
386	
387	  // Envelope sniffing: a backup envelope has log/state at the top level.
388	  // If we see those without a program, the caller picked the wrong file
389	  // for this button — point them at the backup importer.
390	  const looksLikeEnvelope = 'log' in data || 'state' in data;
391	  let candidate: unknown;
392	  if ('program' in data) {
393	    candidate = data.program;
394	  } else if (looksLikeEnvelope) {
395	    throw new Error(
396	      'No program in this file. To restore a backup with log + state, use the Import Backup button in the toolbar.',
397	    );
398	  } else {
399	    candidate = data;
400	  }
401	
402	  const migrated = migrateProgram(candidate);
403	  if (!migrated) {
404	    throw new Error('Invalid program file: missing meta or phases');
405	  }
406	  await saveProgram(migrated.program);
407	  return { exerciseMapping: migrated.stats };
408	}
409	
410	// Convenience for tests: read a File and apply.
411	export async function applyImportFromFile(
412	  file: File,
413	  opts?: { applyState?: boolean },
414	): Promise<ImportResult> {
415	  const text = await file.text();
416	  const parsed: unknown = JSON.parse(text);
417	  return applyImport(parsed, opts);
418	}
419	
420	export async function applyProgramImportFromFile(
421	  file: File,
422	): Promise<ProgramImportResult> {
423	  const text = await file.text();
424	  const parsed: unknown = JSON.parse(text);
425	  return applyProgramImport(parsed);
426	}
427	
428	export type { LogMap, Program };
